import { useEffect, useState } from "react";
import axios from "axios";

export default function Dashboard() {
  const [productos, setProductos] = useState([]);
  const [nuevoProducto, setNuevoProducto] = useState({
    Nombre: "",
    Precio: "",
    Stock: "",
  });
  const [editando, setEditando] = useState(null);

  const obtenerProductos = async () => {
    try {
      const res = await axios.get("http://localhost:5000/api/productos");
      setProductos(res.data);
    } catch (error) {
      console.error("Error al obtener productos:", error);
    }
  };

  useEffect(() => {
    obtenerProductos();
  }, []);

  const handleChange = (e) => {
    setNuevoProducto({ ...nuevoProducto, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      if (editando) {
        await axios.put(
          `http://localhost:5000/api/productos/${editando.ProductoID}`,
          nuevoProducto
        );
      } else {
        await axios.post("http://localhost:5000/api/productos", nuevoProducto);
      }
      setNuevoProducto({ Nombre: "", Precio: "", Stock: "" });
      setEditando(null);
      obtenerProductos();
    } catch (error) {
      console.error("Error al guardar producto:", error);
    }
  };

  const editarProducto = (producto) => {
    setNuevoProducto({
      Nombre: producto.Nombre || "",
      Precio: producto.Precio || "",
      Stock: producto.Stock || "",
    });
    setEditando(producto);
  };

  const eliminarProducto = async (ProductoID) => {
    if (window.confirm("¿Seguro que deseas eliminar este producto?")) {
      try {
        await axios.delete(`http://localhost:5000/api/productos/${ProductoID}`);
        obtenerProductos();
      } catch (error) {
        console.error("Error al eliminar producto:", error);
      }
    }
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-gray-50 to-blue-100 p-8">
      <div className="max-w-5xl mx-auto">
        <h1 className="text-4xl font-extrabold text-center mb-10 text-blue-700">
          🛍️ Panel de Administración de Productos
        </h1>

        {/* Formulario */}
        <div className="bg-white shadow-lg rounded-2xl p-8 mb-10 transition-all duration-300 hover:shadow-2xl">
          <h2 className="text-2xl font-semibold mb-6 text-gray-700 border-b pb-3">
            {editando ? "✏️ Editar Producto" : "➕ Agregar Producto"}
          </h2>

          <form onSubmit={handleSubmit} className="grid grid-cols-1 sm:grid-cols-3 gap-6">
            <input
              type="text"
              name="Nombre"
              value={nuevoProducto.Nombre}
              onChange={handleChange}
              placeholder="Nombre del producto"
              className="border border-gray-300 p-3 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-400"
              required
            />
            <input
              type="number"
              name="Precio"
              value={nuevoProducto.Precio}
              onChange={handleChange}
              placeholder="Precio"
              className="border border-gray-300 p-3 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-400"
              required
            />
            <input
              type="number"
              name="Stock"
              value={nuevoProducto.Stock}
              onChange={handleChange}
              placeholder="Stock"
              className="border border-gray-300 p-3 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-400"
              required
            />

            <div className="col-span-full flex gap-3 mt-2">
              <button
                type="submit"
                className="bg-blue-600 hover:bg-blue-700 text-white font-semibold px-6 py-2 rounded-lg transition duration-300"
              >
                {editando ? "Actualizar" : "Agregar"}
              </button>

              {editando && (
                <button
                  type="button"
                  onClick={() => {
                    setEditando(null);
                    setNuevoProducto({ Nombre: "", Precio: "", Stock: "" });
                  }}
                  className="bg-gray-500 hover:bg-gray-600 text-white font-semibold px-6 py-2 rounded-lg transition duration-300"
                >
                  Cancelar
                </button>
              )}
            </div>
          </form>
        </div>

        {/* Tabla */}
        <div className="bg-white shadow-md rounded-2xl overflow-hidden">
          <table className="min-w-full border-collapse">
            <thead className="bg-blue-600 text-white">
              <tr>
                <th className="py-3 px-4 text-left">ID</th>
                <th className="py-3 px-4 text-left">Nombre</th>
                <th className="py-3 px-4 text-left">Precio</th>
                <th className="py-3 px-4 text-left">Stock</th>
                <th className="py-3 px-4 text-center">Acciones</th>
              </tr>
            </thead>
            <tbody>
              {productos.length === 0 ? (
                <tr>
                  <td colSpan="5" className="text-center py-6 text-gray-500">
                    No hay productos registrados 😕
                  </td>
                </tr>
              ) : (
                productos.map((p) => (
                  <tr
                    key={p.ProductoID}
                    className="border-b hover:bg-gray-50 transition duration-200"
                  >
                    <td className="py-3 px-4">{p.ProductoID}</td>
                    <td className="py-3 px-4 font-medium">{p.Nombre}</td>
                    <td className="py-3 px-4">${p.Precio}</td>
                    <td className="py-3 px-4">{p.Stock}</td>
                    <td className="py-3 px-4 flex justify-center gap-3">
                      <button
                        onClick={() => editarProducto(p)}
                        className="bg-yellow-400 hover:bg-yellow-500 text-white font-semibold px-4 py-1 rounded-lg transition"
                      >
                        Editar
                      </button>
                      <button
                        onClick={() => eliminarProducto(p.ProductoID)}
                        className="bg-red-500 hover:bg-red-600 text-white font-semibold px-4 py-1 rounded-lg transition"
                      >
                        Eliminar
                      </button>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}
